const express = require('express');
const router = express.Router();
const UserModel = require('../models/userModel');

// Get all users
router.get('/', async (req, res) => {
    try {
        const users = await UserModel.findAll();
        res.json(users);
    } catch (err) {
        console.error('Error fetching users:', err.message);
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

// Get user by ID
router.get('/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const user = await UserModel.findById(id);
        if (!user) {
            return res.status(404).json({ error: 'User not found' });
        }
        res.json(user);
    } catch (err) {
        console.error(`Error fetching user with ID ${req.params.id}:`, err.message);
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

// Create a new user
router.post('/', async (req, res) => {
    try {
        const { name, email, age } = req.body;
        if (!name || !email) {
            return res.status(400).json({ error: 'Name and email are required' });
        }
        const newUser = await UserModel.create(name, email, age);
        res.status(201).json(newUser);
    } catch (err) {
        console.error('Error creating user:', err.message);
        if (err.code === '23505') { // Unique violation error code for PostgreSQL
            return res.status(409).json({ error: 'Email already exists' });
        }
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

// Update a user by ID
router.put('/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const { name, email, age } = req.body;
        if (!name || !email) {
            return res.status(400).json({ error: 'Name and email are required for update' });
        }
        const updatedUser = await UserModel.update(id, name, email, age);
        if (!updatedUser) {
            return res.status(404).json({ error: 'User not found' });
        }
        res.json(updatedUser);
    } catch (err) {
        console.error(`Error updating user with ID ${req.params.id}:`, err.message);
        if (err.code === '23505') {
            return res.status(409).json({ error: 'Email already exists' });
        }
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

// Delete a user by ID
router.delete('/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const deletedUser = await UserModel.delete(id);
        if (!deletedUser) {
            return res.status(404).json({ error: 'User not found' });
        }
        res.json({ message: 'User deleted successfully', deletedUser });
    } catch (err) {
        console.error(`Error deleting user with ID ${req.params.id}:`, err.message);
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

module.exports = router;

